async updateStudent(id: string, data: any) {
    const student = await this.studentRepository.findById(id);
    if (!student) throw new AppError('Học viên không tồn tại', 404);

    // Business Logic Guard: Validate status transition if requested
    if (data.status) {
      StatusTransitionHelper.validate(student, data.status);
    }

    // 1. Update Core User Data
    const userId = (student.user_id as any)._id || student.user_id;
    const coreFields = [
      'name',
      'first_name',
      'last_name',
      'phone',
      'identity_number',
      'identity_card',
      'email',
      'existing_license_num',
      'existing_license_rank',
    ];
    if (Object.keys(data).some((k) => coreFields.includes(k))) {
      await this.userService.updateUserProfile(userId, data);
    }

    // 2. Map and Update Core Student Attributes (Demographics & Category)
    const demographicUpdate: any = {};
    if (data.city !== undefined) {
      demographicUpdate.region_id =
        data.city === ''
          ? null
          : mongoose.Types.ObjectId.isValid(data.city)
            ? new mongoose.Types.ObjectId(data.city)
            : data.city;
    }
    if (data.region_id !== undefined) {
      demographicUpdate.region_id =
        data.region_id === ''
          ? null
          : mongoose.Types.ObjectId.isValid(data.region_id)
            ? new mongoose.Types.ObjectId(data.region_id)
            : data.region_id;
    }

    // ENSURE: license_category_id is ALSO updated on the Student document, not just CourseStudent
    if (data.rank !== undefined && data.rank !== '') {
      demographicUpdate.license_category_id = await this._resolveLicenseCategoryId(data.rank);
    } else if (data.license_category_id !== undefined && data.license_category_id !== '') {
      demographicUpdate.license_category_id = await this._resolveLicenseCategoryId(data.license_category_id);
    }

    if (data.status !== undefined && data.status !== '') {
      let sanitizedStatus = data.status;
      if (sanitizedStatus === 'Đã xong KSK') sanitizedStatus = 'Đã KSK';
      demographicUpdate.status_detail = sanitizedStatus;
    }

    if (data.lead_manager !== undefined) {
      demographicUpdate.lead_manager = data.lead_manager === '' ? null : data.lead_manager;
    }

