import mongoose, { Schema, Document, Types } from 'mongoose';

export interface ICourseStudent extends Document {
  student_id: Types.ObjectId; // References Student(student_infos)
  course_id: Types.ObjectId; // References Course(course_infos)
  stadium_id?: Types.ObjectId | null;
  teacher_id?: Types.ObjectId | null;
  sale_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  status: 'unfinished' | 'finished' | 'canceled';
  km: number;
  hour: string;
  fee: number;
  paid_fee: number;
  balance?: any; // Treasury balance for this enrollment
  contract_date?: Date | null;
  status_detail?: string;
  progress_flags?: {
    theory_completed: boolean;
    sand_yard_completed: boolean;
    simulation_completed: boolean;
    dat_completed: boolean;
    cabin_completed: boolean;
    graduation_eligible: boolean;
  };
  health_check?: {
    status: string;
    date: Date | null;
    hospital: string | null;
    note: string | null;
  };
  created_at: Date;
  updated_at: Date;
}

const CourseStudentSchema = new Schema<ICourseStudent>(
  {
    student_id: { type: Schema.Types.ObjectId, ref: 'StudentInfos', required: true, index: true },
    course_id: { type: Schema.Types.ObjectId, ref: 'Courses', required: true, index: true },
    stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums', default: null },
    teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
    sale_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
    license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },
    status: {
      type: String,
      enum: ['unfinished', 'finished', 'canceled'],
      default: 'unfinished',
    },
    km: { type: Number, default: 0 },
    hour: { type: String, default: '00:00' },
    fee: { type: Number, default: 0 },
    paid_fee: { type: Number, default: 0 },
    balance: {
      type: Schema.Types.Decimal128,
      default: 0,
      get: (v: any) => (v ? parseFloat(v.toString()) : 0),
    },
    contract_date: { type: Date, default: null },
    status_detail: { type: String, default: 'Chờ KSK' },
    progress_flags: {
      theory_completed: { type: Boolean, default: false },
      sand_yard_completed: { type: Boolean, default: false },
      simulation_completed: { type: Boolean, default: false },
      dat_completed: { type: Boolean, default: false },
      cabin_completed: { type: Boolean, default: false },
      graduation_eligible: { type: Boolean, default: false },
    },
    health_check: {
      status: { type: String, enum: ['Chờ khám', 'Đủ điều kiện', 'Không đủ điều kiện'], default: 'Chờ khám' },
      date: { type: Date, default: null },
      hospital: { type: String, default: null },
      note: { type: String, default: null },
    },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
    collection: 'coursestudents',
  },
);

CourseStudentSchema.index({ student_id: 1, created_at: -1 });
CourseStudentSchema.index({ course_id: 1, created_at: -1 });
CourseStudentSchema.index({ status_detail: 1, created_at: -1 });
CourseStudentSchema.index({ sale_id: 1, created_at: -1 });
CourseStudentSchema.index({ 'progress_flags.dat_completed': 1, status_detail: 1 });
CourseStudentSchema.index({ fee: 1, paid_fee: 1 });

export const CourseStudentModel =
  mongoose.models.CourseStudents ||
  mongoose.model<ICourseStudent>('CourseStudents', CourseStudentSchema, 'coursestudents');

