import express from 'express';
import * as studentController from '@/interface/controllers/student.controller';
import { validate } from '@/interface/middlewares/validation.middleware';
import { paginationMiddleware } from '@/interface/middlewares/pagination.middleware';
import { createStudentSchema } from '@/interface/dtos/student.dto';
import multer from 'multer';
import path from 'path';

const upload = multer({ dest: 'uploads/' });

const router = express.Router();

router.post('/', validate(createStudentSchema), studentController.createStudent);
router.post('/import', upload.single('file'), studentController.importStudents);
router.get('/import-template', studentController.downloadTemplate);
router.get('/import-stats', studentController.getImportStats);
router.get('/', paginationMiddleware, studentController.getAllStudents);
router.get('/export', studentController.exportStudents);
router.get('/license-categories', studentController.getLicenseCategories);
router.get('/leads', studentController.getLeads);
router.get('/:id/history', paginationMiddleware, studentController.getStudentHistory);
router.get('/:id', studentController.getStudentById);
router.put('/:id', studentController.updateStudent);
router.delete('/bulk', studentController.bulkDeleteStudents);
router.delete('/:id', studentController.deleteStudent);

export default router;

