  async bulkDeleteStudents(ids: string[], currentUser?: any) {
    if (!ids || ids.length === 0) {
      throw new Error('Danh sách ID không được để trống');
    }

    // 1. Verify existence and ownership for all
    // We could optimize this, but for safety we check all
    for (const id of ids) {
      await this.getStudentById(id, currentUser);
    }

    // 2. Cascade delete enrollments for all
    await CourseStudentModel.deleteMany({ student_id: { $in: ids } });

    // 3. Batch delete students
    return await this.studentRepository.deleteMany(ids);
  }

